import{_ as t,o as i,c as l,a3 as a}from"./chunks/framework.ZM1D-rQ5.js";const p=JSON.parse('{"title":"Builder Elements","description":"","frontmatter":{},"headers":[],"relativePath":"builder/elements.md","filePath":"builder/elements.md","lastUpdated":1781554731000}'),o={name:"builder/elements.md"};function n(r,e,s,d,c,h){return i(),l("div",null,[...e[0]||(e[0]=[a('<h1 id="builder-elements" tabindex="-1">Builder Elements <a class="header-anchor" href="#builder-elements" aria-label="Permalink to &quot;Builder Elements&quot;">​</a></h1><p>Elements are the content blocks inside columns. Falcon Builder ships with <strong>22 built-in element types</strong>.</p><h2 id="text-elements" tabindex="-1">Text Elements <a class="header-anchor" href="#text-elements" aria-label="Permalink to &quot;Text Elements&quot;">​</a></h2><h3 id="heading" tabindex="-1">Heading <a class="header-anchor" href="#heading" aria-label="Permalink to &quot;Heading&quot;">​</a></h3><p>A title or subtitle block (H1–H6).</p><p><strong>Settings:</strong></p><ul><li>Text content</li><li>Tag (H1–H6)</li><li>Font size, weight, line height</li><li>Letter spacing</li><li>Text alignment (left, center, right)</li><li>Color</li><li>CSS Class / CSS ID</li></ul><h3 id="title" tabindex="-1">Title <a class="header-anchor" href="#title" aria-label="Permalink to &quot;Title&quot;">​</a></h3><p>A dynamic post/page title element — automatically pulls the current content&#39;s title. Useful in templates, header builder, and single post layouts.</p><p><strong>Settings:</strong></p><ul><li>Tag (H1–H6)</li><li>Font size, weight, color</li><li>Text alignment</li></ul><h3 id="text-block" tabindex="-1">Text Block <a class="header-anchor" href="#text-block" aria-label="Permalink to &quot;Text Block&quot;">​</a></h3><p>A rich-text paragraph block with a WYSIWYG editor.</p><p><strong>Settings:</strong></p><ul><li>Content (WYSIWYG)</li><li>Font size, line height</li><li>Text alignment</li><li>Color</li></ul><h3 id="text" tabindex="-1">Text <a class="header-anchor" href="#text" aria-label="Permalink to &quot;Text&quot;">​</a></h3><p>A simple single-line text element with dynamic source support.</p><p><strong>Settings:</strong></p><ul><li>Text content or dynamic source (post title, site name, etc.)</li><li>Font size, weight, color</li><li>Text alignment</li></ul><h3 id="ticker" tabindex="-1">Ticker <a class="header-anchor" href="#ticker" aria-label="Permalink to &quot;Ticker&quot;">​</a></h3><p>A horizontally scrolling text marquee — great for announcements or news tickers.</p><p><strong>Settings:</strong></p><ul><li>Items (list of text lines)</li><li>Speed</li><li>Direction (left / right)</li><li>Separator style</li><li>Font size, color, background</li></ul><hr><h2 id="media-elements" tabindex="-1">Media Elements <a class="header-anchor" href="#media-elements" aria-label="Permalink to &quot;Media Elements&quot;">​</a></h2><h3 id="image" tabindex="-1">Image <a class="header-anchor" href="#image" aria-label="Permalink to &quot;Image&quot;">​</a></h3><p>A single image with optional link.</p><p><strong>Settings:</strong></p><ul><li><strong>Dynamic Source</strong> — pull the image automatically from context: <ul><li><code>Feature Image</code> — the current post&#39;s featured image</li><li><code>Author Avatar</code> — the post author&#39;s avatar</li><li><code>Site Logo</code> — the logo set in Customizer → General → Logo</li></ul></li><li>Image URL (media library picker, used when no dynamic source is selected)</li><li>Alt text</li><li>Width / Max Width</li><li><strong>Link URL</strong> — static URL or dynamic source: <ul><li><code>Site URL</code> — links to the site homepage</li><li><code>Post URL</code> — links to the current post&#39;s permalink</li></ul></li><li>Link target (<code>_blank</code>, <code>_self</code>)</li><li>Aspect ratio + focus point (X/Y) for cropped images</li><li>Border radius, border (per-side), box shadow</li><li>Hover effect</li><li>Sticky width (shrinks when header is sticky)</li></ul><h3 id="gallery" tabindex="-1">Gallery <a class="header-anchor" href="#gallery" aria-label="Permalink to &quot;Gallery&quot;">​</a></h3><p>A responsive image grid or slider.</p><p><strong>Settings:</strong></p><ul><li>Images (multi-select from media library)</li><li>Layout: grid / masonry / slider</li><li>Columns (2, 3, 4)</li><li>Gap between images</li><li>Lightbox on click</li></ul><h3 id="video" tabindex="-1">Video <a class="header-anchor" href="#video" aria-label="Permalink to &quot;Video&quot;">​</a></h3><p>Embed YouTube, Vimeo, or self-hosted video.</p><p><strong>Settings:</strong></p><ul><li>Video URL</li><li>Autoplay, Loop, Mute</li><li>Show/hide controls</li><li>Aspect ratio</li></ul><hr><h2 id="interactive-elements" tabindex="-1">Interactive Elements <a class="header-anchor" href="#interactive-elements" aria-label="Permalink to &quot;Interactive Elements&quot;">​</a></h2><h3 id="counter" tabindex="-1">Counter <a class="header-anchor" href="#counter" aria-label="Permalink to &quot;Counter&quot;">​</a></h3><p>An animated number that counts up on scroll.</p><p><strong>Settings:</strong></p><ul><li>Starting number</li><li>Final number</li><li>Duration (ms)</li><li>Prefix (e.g., <code>$</code>)</li><li>Suffix (e.g., <code>+</code>, <code>k</code>)</li><li>Label (caption below number)</li><li>Font size, color</li></ul><p><strong>Example:</strong> <code>$</code> → <code>10,000</code> → <code>+</code> counted from <code>0</code> in <code>2000ms</code>.</p><h3 id="accordion" tabindex="-1">Accordion <a class="header-anchor" href="#accordion" aria-label="Permalink to &quot;Accordion&quot;">​</a></h3><p>Collapsible FAQ / content sections.</p><p><strong>Settings:</strong></p><ul><li>Items (title + content pairs)</li><li>Single open mode (collapse others on open)</li><li>Icon (arrow / plus)</li><li>Icon position (left / right)</li><li>Colors, border, padding</li></ul><h3 id="tabs" tabindex="-1">Tabs <a class="header-anchor" href="#tabs" aria-label="Permalink to &quot;Tabs&quot;">​</a></h3><p>Tabbed content panels.</p><p><strong>Settings:</strong></p><ul><li>Tabs (label + content pairs)</li><li>Default active tab</li><li>Tab alignment (left, center, right)</li><li>Style (underline / pill / border)</li></ul><hr><h2 id="layout-elements" tabindex="-1">Layout Elements <a class="header-anchor" href="#layout-elements" aria-label="Permalink to &quot;Layout Elements&quot;">​</a></h2><h3 id="button" tabindex="-1">Button <a class="header-anchor" href="#button" aria-label="Permalink to &quot;Button&quot;">​</a></h3><p>A call-to-action button.</p><p><strong>Settings:</strong></p><ul><li>Text</li><li>Link URL + target</li><li>Style: solid / outline / ghost</li><li>Colors: background, text, border</li><li>Hover: background, text, border</li><li>Border radius</li><li>Padding</li><li>Icon (FontAwesome class + position)</li><li>Full width toggle</li></ul><h3 id="card" tabindex="-1">Card <a class="header-anchor" href="#card" aria-label="Permalink to &quot;Card&quot;">​</a></h3><p>A content card with image, title, description, and optional button.</p><p><strong>Settings:</strong></p><ul><li>Image (media library)</li><li>Title, description</li><li>Button text + link</li><li>Border radius, shadow</li><li>Hover effect</li></ul><h3 id="spacer" tabindex="-1">Spacer <a class="header-anchor" href="#spacer" aria-label="Permalink to &quot;Spacer&quot;">​</a></h3><p>Empty vertical space for layout control.</p><p><strong>Settings:</strong></p><ul><li>Height (px)</li><li>Desktop / Tablet / Mobile heights (responsive)</li></ul><h3 id="icon-box" tabindex="-1">Icon Box <a class="header-anchor" href="#icon-box" aria-label="Permalink to &quot;Icon Box&quot;">​</a></h3><p>An icon paired with a title and description.</p><p><strong>Settings:</strong></p><ul><li>Icon (FontAwesome class)</li><li>Icon size, color, background</li><li>Title</li><li>Description</li><li>Link</li><li>Layout: icon above / icon left</li></ul><h3 id="icon-list" tabindex="-1">Icon List <a class="header-anchor" href="#icon-list" aria-label="Permalink to &quot;Icon List&quot;">​</a></h3><p>A styled list with icons.</p><p><strong>Settings:</strong></p><ul><li>Items (icon + text pairs)</li><li>Icon color</li><li>Text size, color</li><li>Gap between items</li></ul><hr><h2 id="post-dynamic-elements" tabindex="-1">Post &amp; Dynamic Elements <a class="header-anchor" href="#post-dynamic-elements" aria-label="Permalink to &quot;Post &amp; Dynamic Elements&quot;">​</a></h2><h3 id="post-grid" tabindex="-1">Post Grid <a class="header-anchor" href="#post-grid" aria-label="Permalink to &quot;Post Grid&quot;">​</a></h3><p>Dynamically display posts in a grid.</p><p><strong>Settings:</strong></p><ul><li>Post type (post / page / product / CPT)</li><li>Limit (number of posts)</li><li>Category filter</li><li>Tag filter</li><li>Order by (date, title, random)</li><li>Order (ASC / DESC)</li><li>Columns (1–4)</li><li>Show: thumbnail, title, excerpt, date, author, read more button</li><li>Pagination on/off</li></ul><h3 id="post-content" tabindex="-1">Post Content <a class="header-anchor" href="#post-content" aria-label="Permalink to &quot;Post Content&quot;">​</a></h3><p>Renders the full content of the current post — used in single post/page templates.</p><h3 id="post-meta" tabindex="-1">Post Meta <a class="header-anchor" href="#post-meta" aria-label="Permalink to &quot;Post Meta&quot;">​</a></h3><p>Displays post metadata — author, date, category, tags, etc.</p><p><strong>Settings:</strong></p><ul><li>Select which meta fields to show</li><li>Date format</li><li>Separator style</li></ul><h3 id="star-rating" tabindex="-1">Star Rating <a class="header-anchor" href="#star-rating" aria-label="Permalink to &quot;Star Rating&quot;">​</a></h3><p>Display a static star rating.</p><p><strong>Settings:</strong></p><ul><li>Rating value (0–5)</li><li>Icon color</li><li>Size</li></ul><hr><h2 id="advanced-elements" tabindex="-1">Advanced Elements <a class="header-anchor" href="#advanced-elements" aria-label="Permalink to &quot;Advanced Elements&quot;">​</a></h2><h3 id="html" tabindex="-1">HTML <a class="header-anchor" href="#html" aria-label="Permalink to &quot;HTML&quot;">​</a></h3><p>A raw HTML block — paste any embed code or custom markup.</p><p><strong>Settings:</strong></p><ul><li>Raw HTML / embed code</li></ul><h3 id="menu" tabindex="-1">Menu <a class="header-anchor" href="#menu" aria-label="Permalink to &quot;Menu&quot;">​</a></h3><p>Render a navigation menu inline inside the builder canvas — primarily used in the header builder.</p><p><strong>Settings:</strong></p><ul><li>Select menu (by location or slug)</li><li>Layout: horizontal / vertical</li><li>Mega menu support</li></ul><hr><h2 id="element-settings-all-elements" tabindex="-1">Element Settings (All Elements) <a class="header-anchor" href="#element-settings-all-elements" aria-label="Permalink to &quot;Element Settings (All Elements)&quot;">​</a></h2><p>Every element has these shared settings in the <strong>General</strong> tab:</p><h3 id="element-visibility" tabindex="-1">Element Visibility <a class="header-anchor" href="#element-visibility" aria-label="Permalink to &quot;Element Visibility&quot;">​</a></h3><p>Control which devices see this element:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ Desktop ] [ Tablet ] [ Mobile ]</span></span></code></pre></div><p>Click a device to toggle visibility. Useful for showing different content per breakpoint.</p><h3 id="css-class" tabindex="-1">CSS Class <a class="header-anchor" href="#css-class" aria-label="Permalink to &quot;CSS Class&quot;">​</a></h3><p>Add one or more custom CSS classes to the element wrapper.</p><h3 id="css-id" tabindex="-1">CSS ID <a class="header-anchor" href="#css-id" aria-label="Permalink to &quot;CSS ID&quot;">​</a></h3><p>Add a unique ID for anchor links or JavaScript targeting.</p><h3 id="extra-options-tab" tabindex="-1">Extra Options Tab <a class="header-anchor" href="#extra-options-tab" aria-label="Permalink to &quot;Extra Options Tab&quot;">​</a></h3><ul><li>Custom CSS (applied to this element only)</li><li>Hover effects</li><li>Animation on scroll (fade, slide, zoom)</li><li>Z-index</li><li>Position (static, relative, absolute)</li></ul><hr><h2 id="dynamic-values" tabindex="-1">Dynamic Values <a class="header-anchor" href="#dynamic-values" aria-label="Permalink to &quot;Dynamic Values&quot;">​</a></h2><p>Many text fields support dynamic tokens — they&#39;re replaced at render time:</p><table tabindex="0"><thead><tr><th>Token</th><th>Replaced with</th></tr></thead><tbody><tr><td><code>{post_title}</code></td><td>Current post&#39;s title</td></tr><tr><td><code>{post_excerpt}</code></td><td>Post excerpt</td></tr><tr><td><code>{post_date}</code></td><td>Published date</td></tr><tr><td><code>{site_name}</code></td><td>Site name from settings</td></tr><tr><td><code>{current_date}</code></td><td>Today&#39;s date</td></tr><tr><td><code>{author_name}</code></td><td>Post author&#39;s name</td></tr></tbody></table><p><strong>Example:</strong> Set a Heading text to <code>Welcome back, {author_name}!</code> for a personalized greeting.</p>',118)])])}const m=t(o,[["render",n]]);export{p as __pageData,m as default};
